#include <stdio.h>
#include <string.h>
#define MAX_R 500
#define MAX_C 500
int sieve[MAX_R + 1];
int main() {
    int T, R, C, i, j, monsters = 0;
    char map[MAX_R][MAX_C + 1];
    int primes[MAX_R + 1];
    int primeCount = 0;
    scanf("%d", &T);
    for (i = 2; i <= MAX_R; i++) {
        sieve[i] = 1;
    }
    for (i = 2; i <= MAX_R; i++) {
        if (sieve[i]) {
            for (j = i * i; j <= MAX_R; j += i) {
                sieve[j] = 0;
            }
        }
    }
    for (i = 2; i <= MAX_R; i++) {
        if (sieve[i]) {
            primes[primeCount++] = i;
        }
    }
    while (T--) {
        scanf("%d %d", &R, &C);
        for (i = 0; i < R; i++) {
            scanf("%s", map[i]);
        }
        monsters = 0;
        for (i = 0; i < R; i++) {
            for (j = 0; j < C; j++) {
                int L = 0, R = 0, T = 0, B = 0;
                int min = MAX_R;
                for (int k = j - 1; k >= 0; k--) {
                    if (map[i][k] == '^') {
                        L++;
                    } else {
                        break;
                    }
                }
                for (int k = j + 1; k < C; k++) {
                    if (map[i][k] == '^') {
                        R++;
                    } else {
                        break;
                    }
                }
                for (int k = i - 1; k >= 0; k--) {
                    if (map[k][j] == '^') {
                        T++;
                    } else {
                        break;
                    }
                }
                for (int k = i + 1; k < R; k++) {
                    if (map[k][j] == '^') {
                        B++;
                    } else {
                        break;
                    }
                }
                min = (L < R ? L : R);
                min = (min < T ? min : T);
                min = (min < B ? min : B);
                for (int k = 0; k < primeCount; k++) {
                    if (primes[k] <= min && map[i][j] == '^') {
                        monsters++;
                        break;
                    }
                }
            }
        }
        printf("%d\n", monsters);
    }
    return 0;
}

