import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int R = sc.nextInt();
            int C = sc.nextInt();
            String[] map = new String[R];
            for (int i = 0; i < R; i++) {
                map[i] = sc.next();
            }
            int monsters = 0;
            for (int i = 0; i < R; i++) {
                for (int j = 0; j < C; j++) {
                    int L = 0, R = 0, T = 0, B = 0;
                    int min = Integer.MAX_VALUE;
                    for (int k = j - 1; k >= 0; k--) {
                        if (map[i].charAt(k) == '^') {
                            L++;
                        } else {
                            break;
                        }
                    }
                    for (int k = j + 1; k < C; k++) {
                        if (map[i].charAt(k) == '^') {
                            R++;
                        } else {
                            break;
                        }
                    }
                    for (int k = i - 1; k >= 0; k--) {
                        if (map[k].charAt(j) == '^') {
                            T++;
                        } else {
                            break;
                        }
                    }
                    for (int k = i + 1; k < R; k++) {
                        if (map[k].charAt(j) == '^') {
                            B++;
                        } else {
                            break;
                        }
                    }
                    min = Math.min(L, R);
                    min = Math.min(min, T);
                    min = Math.min(min, B);
                    for (int k = 2; k <= min; k++) {
                        if (isPrime(k)) {
                            monsters++;
                            break;
                        }
                    }
                }
            }
            System.out.println(monsters);
        }
    }
    public static boolean isPrime(int n) {
        if (n <= 1) {
            return false;
        }
        for (int i = 2; i * i <= n; i++) {
            if (n % i == 0) {
                return false;
            }
        }
        return true;
    }
}

